def update(self, iterable, **kwds):
    # Recursively merge dict-like values (including `Features`/`Sequence` wrapping a dict)
    # instead of letting the new value overwrite the existing one entirely.
    def _as_dict(value):
        if isinstance(value, dict):
            return value
        if isinstance(value, Sequence) and isinstance(value.feature, dict):
            return value.feature
        return None

    def _merged_value(key, value):
        if key in self:
            current_dict = _as_dict(self[key])
            new_dict = _as_dict(value)
            if current_dict is not None and new_dict is not None:
                current_dict.update(new_dict)
                return self[key]
        return value

    if hasattr(iterable, "keys"):
        for key in iterable.keys():
            self[key] = _merged_value(key, iterable[key])
    else:
        for key, value in iterable:
            self[key] = _merged_value(key, value)
    for key in kwds:
        self[key] = _merged_value(key, kwds[key])

